const text = $input.item.json.message.text || '';
const chatId = $input.item.json.message.chat.id;
const lowerText = text.toLowerCase().trim();

let command = 'unknown';
if (lowerText.startsWith('dors')) {
  command = 'dors';
} else if (lowerText.startsWith('reveil') || lowerText.startsWith('réveil')) {
  command = 'reveil';
} else if (lowerText.startsWith('stats') || lowerText.startsWith('stat')) {
  command = 'stats';
}

const match = text.match(/(\d{1,2})[h:](\d{2})/);
let heures = null;
let minutes = null;
if (match) {
  heures = parseInt(match[1]);
  minutes = parseInt(match[2]);
}

return {
  command,
  heures,
  minutes,
  chatId,
  rawText: text
};

const { heures, minutes, chatId } = $input.item.json;

if (heures === null || minutes === null || heures > 23 || minutes > 59) {
  return {
    chatId,
    reply: "❌ Format invalide. Utilise : dors HH:MM (ex: dors 23:30)"
  };
}

const heureCoucher = `${String(heures).padStart(2, '0')}:${String(minutes).padStart(2, '0')}`;

const staticData = $getWorkflowStaticData('global');
staticData[`coucher_${chatId}`] = heureCoucher;
staticData[`coucher_timestamp_${chatId}`] = Date.now();

const hStr = `${heures}h${String(minutes).padStart(2, '0')}`;

return {
  chatId,
  reply: `😴 Bonne nuit ! Coucher enregistre a ${hStr}.\nEnvoie \"reveil HH:MM\" demain matin.`
};

const { heures, minutes, chatId } = $input.item.json;

if (heures === null || minutes === null || heures > 23 || minutes > 59) {
  return {
    chatId,
    reply: "❌ Format invalide. Utilise : reveil HH:MM (ex: reveil 07:15)"
  };
}

const staticData = $getWorkflowStaticData('global');
const coucherStr = staticData[`coucher_${chatId}`];

if (!coucherStr) {
  return {
    chatId,
    reply: "❌ Aucune heure de coucher enregistree.\nEnvoie d'abord : dors HH:MM"
  };
}

const [hCoucher, mCoucher] = coucherStr.split(':').map(Number);

let minutesCoucher = hCoucher * 60 + mCoucher;
let minutesReveil = heures * 60 + minutes;

let dureeMinutes;
if (minutesReveil >= minutesCoucher) {
  dureeMinutes = minutesReveil - minutesCoucher;
} else {
  dureeMinutes = (24 * 60 - minutesCoucher) + minutesReveil;
}

if (dureeMinutes > 18 * 60) {
  return {
    chatId,
    reply: `⚠️ Duree calculee de ${Math.floor(dureeMinutes/60)}h${dureeMinutes%60} - ca semble incorrect.\nVerifie tes heures (coucher: ${coucherStr}, reveil: ${heures}:${String(minutes).padStart(2,'0')}).`
  };
}

const dureeH = Math.floor(dureeMinutes / 60);
const dureeM = dureeMinutes % 60;

let commentaire, emoji;
if (dureeMinutes >= 8 * 60) {
  commentaire = "Excellente nuit !";
  emoji = "🌟";
} else if (dureeMinutes >= 7 * 60) {
  commentaire = "Bonne nuit !";
  emoji = "✅";
} else if (dureeMinutes >= 6 * 60) {
  commentaire = "Correct, mais essaie de dormir plus.";
  emoji = "😐";
} else {
  commentaire = "Insuffisant ! Pense a te coucher plus tot.";
  emoji = "⚠️";
}

const now = new Date();
const dateNuit = new Date(now);
if (hCoucher >= 18) {
  dateNuit.setDate(dateNuit.getDate() - 1);
}
const jourNuit = `${String(dateNuit.getDate()).padStart(2, '0')}/${String(dateNuit.getMonth() + 1).padStart(2, '0')}`;

const hCoucherStr = `${String(hCoucher).padStart(2, '0')}h${String(mCoucher).padStart(2, '0')}`;
const hReveilStr = `${String(heures).padStart(2, '0')}h${String(minutes).padStart(2, '0')}`;
const dureeStr = `${dureeH}h${String(dureeM).padStart(2, '0')}`;

const reply = `🛏️ Nuit du ${jourNuit} - Tu as dormi ${dureeStr}.\nCoucher : ${hCoucherStr} | Reveil : ${hReveilStr}\n${emoji} ${commentaire}`;

// === SAUVEGARDER L'HISTORIQUE ===
if (!staticData[`historique_${chatId}`]) {
  staticData[`historique_${chatId}`] = [];
}
staticData[`historique_${chatId}`].push({
  date: jourNuit,
  timestamp: Date.now(),
  coucher: coucherStr,
  reveil: `${String(heures).padStart(2, '0')}:${String(minutes).padStart(2, '0')}`,
  dureeMinutes: dureeMinutes
});

// Garder max 180 jours (6 mois)
if (staticData[`historique_${chatId}`].length > 180) {
  staticData[`historique_${chatId}`] = staticData[`historique_${chatId}`].slice(-180);
}

delete staticData[`coucher_${chatId}`];
delete staticData[`coucher_timestamp_${chatId}`];

return { chatId, reply };

const chatId = $input.item.json.chatId;
const staticData = $getWorkflowStaticData('global');
const historique = staticData[`historique_${chatId}`] || [];

if (historique.length === 0) {
  return {
    chatId,
    reply: "📊 Aucune donnee de sommeil enregistree.\nCommence par envoyer : dors HH:MM",
    chartUrl: ''
  };
}

const now = Date.now();
const msJour = 24 * 60 * 60 * 1000;

// Filtrer par periodes
const semaine = historique.filter(h => (now - h.timestamp) <= 7 * msJour);
const mois = historique.filter(h => (now - h.timestamp) <= 30 * msJour);
const sixMois = historique.filter(h => (now - h.timestamp) <= 180 * msJour);

// Calcul de moyenne
function moyenne(arr) {
  if (arr.length === 0) return null;
  const total = arr.reduce((sum, h) => sum + h.dureeMinutes, 0);
  return Math.round(total / arr.length);
}

function formatDuree(min) {
  if (min === null) return 'Pas de donnees';
  return `${Math.floor(min / 60)}h${String(min % 60).padStart(2, '0')}`;
}

function getEmoji(min) {
  if (min === null) return '';
  if (min >= 480) return '🌟';
  if (min >= 420) return '✅';
  if (min >= 360) return '😐';
  return '⚠️';
}

const moySemaine = moyenne(semaine);
const moyMois = moyenne(mois);
const moySixMois = moyenne(sixMois);

// === TEXTE DU RESUME ===
let reply = `📊 STATISTIQUES SOMMEIL\n`;
reply += `━━━━━━━━━━━━━━━━━━━━━\n`;
reply += `\n📅 Semaine (${semaine.length} nuits)\n`;
reply += `   Moyenne : ${formatDuree(moySemaine)} ${getEmoji(moySemaine)}\n`;
reply += `\n🗓️ Mois (${mois.length} nuits)\n`;
reply += `   Moyenne : ${formatDuree(moyMois)} ${getEmoji(moyMois)}\n`;
reply += `\n📆 6 mois (${sixMois.length} nuits)\n`;
reply += `   Moyenne : ${formatDuree(moySixMois)} ${getEmoji(moySixMois)}\n`;

// Meilleure et pire nuit du mois
if (mois.length > 0) {
  const best = mois.reduce((a, b) => a.dureeMinutes > b.dureeMinutes ? a : b);
  const worst = mois.reduce((a, b) => a.dureeMinutes < b.dureeMinutes ? a : b);
  reply += `\n🏆 Meilleure nuit du mois : ${formatDuree(best.dureeMinutes)} (${best.date})`;
  reply += `\n😴 Pire nuit du mois : ${formatDuree(worst.dureeMinutes)} (${worst.date})`;
}

// === GRAPHIQUE QUICKCHART ===
// Prendre les 30 derniers jours pour le graphe
const dataGraph = mois.slice(-30);
const labels = dataGraph.map(h => h.date);
const values = dataGraph.map(h => +(h.dureeMinutes / 60).toFixed(2));

// Couleurs selon la duree
const colors = values.map(v => {
  if (v >= 8) return 'rgba(46, 204, 113, 0.8)';
  if (v >= 7) return 'rgba(52, 152, 219, 0.8)';
  if (v >= 6) return 'rgba(241, 196, 15, 0.8)';
  return 'rgba(231, 76, 60, 0.8)';
});

const chartConfig = {
  type: 'bar',
  data: {
    labels: labels,
    datasets: [{
      label: 'Heures de sommeil',
      data: values,
      backgroundColor: colors,
      borderRadius: 4
    }]
  },
  options: {
    plugins: {
      title: {
        display: true,
        text: 'Historique de sommeil',
        font: { size: 18 },
        color: '#ffffff'
      },
      legend: { display: false },
      annotation: {
        annotations: {
          line7h: {
            type: 'line',
            yMin: 7,
            yMax: 7,
            borderColor: 'rgba(46, 204, 113, 0.5)',
            borderWidth: 2,
            borderDash: [6, 6],
            label: {
              display: true,
              content: '7h objectif',
              position: 'end',
              color: '#2ecc71',
              font: { size: 10 }
            }
          }
        }
      }
    },
    scales: {
      y: {
        beginAtZero: false,
        min: 0,
        max: 12,
        title: { display: true, text: 'Heures', color: '#cccccc' },
        ticks: { color: '#cccccc' },
        grid: { color: 'rgba(255,255,255,0.1)' }
      },
      x: {
        ticks: { color: '#cccccc', maxRotation: 45 },
        grid: { display: false }
      }
    }
  }
};

const chartUrl = `https://quickchart.io/chart?c=${encodeURIComponent(JSON.stringify(chartConfig))}&w=800&h=400&bkg=rgb(30,30,30)`;

// === GRAPHE MOYENNES PAR SEMAINE (6 mois) ===
// Regrouper par semaine
const weeks = {};
sixMois.forEach(h => {
  const d = new Date(h.timestamp);
  const weekStart = new Date(d);
  weekStart.setDate(d.getDate() - d.getDay() + 1);
  const weekKey = `${String(weekStart.getDate()).padStart(2,'0')}/${String(weekStart.getMonth()+1).padStart(2,'0')}`;
  if (!weeks[weekKey]) weeks[weekKey] = [];
  weeks[weekKey].push(h.dureeMinutes);
});

const weekLabels = Object.keys(weeks);
const weekAvgs = weekLabels.map(k => +(weeks[k].reduce((a,b) => a+b, 0) / weeks[k].length / 60).toFixed(2));

const chartConfig2 = {
  type: 'line',
  data: {
    labels: weekLabels,
    datasets: [{
      label: 'Moyenne hebdo (h)',
      data: weekAvgs,
      borderColor: 'rgba(52, 152, 219, 1)',
      backgroundColor: 'rgba(52, 152, 219, 0.2)',
      fill: true,
      tension: 0.3,
      pointRadius: 4,
      pointBackgroundColor: 'rgba(52, 152, 219, 1)'
    }]
  },
  options: {
    plugins: {
      title: {
        display: true,
        text: 'Evolution moyenne par semaine',
        font: { size: 18 },
        color: '#ffffff'
      },
      legend: { display: false },
      annotation: {
        annotations: {
          line7h: {
            type: 'line',
            yMin: 7,
            yMax: 7,
            borderColor: 'rgba(46, 204, 113, 0.5)',
            borderWidth: 2,
            borderDash: [6, 6]
          }
        }
      }
    },
    scales: {
      y: {
        min: 4,
        max: 10,
        title: { display: true, text: 'Heures', color: '#cccccc' },
        ticks: { color: '#cccccc' },
        grid: { color: 'rgba(255,255,255,0.1)' }
      },
      x: {
        ticks: { color: '#cccccc', maxRotation: 45 },
        grid: { display: false }
      }
    }
  }
};

const chartUrl2 = `https://quickchart.io/chart?c=${encodeURIComponent(JSON.stringify(chartConfig2))}&w=800&h=400&bkg=rgb(30,30,30)`;

return {
  chatId,
  reply,
  chartUrl,
  chartUrl2
};
